firmware_template.source:
#include "rotary_encoder.h"
#include <Arduino.h>
#define ENC_CLK 32
#define ENC_DT 33
#define ENC_SW 25
static volatile int _pos = 0;
static volatile bool _btn = false;
static int _lastCLK = HIGH;
void IRAM_ATTR _enc_isr() {
  int clk = digitalRead(ENC_CLK);
  if (clk != _lastCLK && clk == LOW) {
    if (digitalRead(ENC_DT) != clk) _pos++; else _pos--;
  }
  _lastCLK = clk;
}
void IRAM_ATTR _btn_isr() { _btn = true; }
void encoder_setup() {
  pinMode(ENC_CLK, INPUT_PULLUP);
  pinMode(ENC_DT, INPUT_PULLUP);
  pinMode(ENC_SW, INPUT_PULLUP);
  attachInterrupt(ENC_CLK, _enc_isr, CHANGE);
  attachInterrupt(ENC_SW, _btn_isr, FALLING);
  Serial.println("[encoder] OK");
}
void encoder_loop() {}
int encoder_get_position(){return _pos;}
bool encoder_button_pressed(){bool b=_btn;_btn=false;return b;}
void encoder_reset(){_pos=0;}
